func solve(s: String, k: Int64): String {
    var result: String = ""
    for c in s {
        if c >= 'a' and c <= 'z' {
            result += c
        } elif c == '*' {
            if not result.empty() {
                result.pop_back()
            }
        } elif c == '#' {
            result += result
        } elif c == '%' {
            reverse(result.begin(), result.end())
        }
    }
    if k >= 0 and k < result.length() {
        return string(1, result[k])
    } else {
        return "."
    }
}
